#include <bits/stdc++.h>
using namespace std;
const int N=1e4+4;
int n,ans;
bool b[N];
vector<int> g[N];
int dfs(int x){
    b[x]=1;
    int flag=-1,len=g[x].size();
    for(int i=0;i<len;i++)
        if(!b[g[x][i]]){
            int t=dfs(g[x][i]);
            if(t==-1)
                flag=1;
            if(t==1 && flag!=1)
                flag=0;
        }
    if(flag==1)
        ans++;
    return flag;
}
int main(){
    cin>>n;
    for(int i=1;i<n;i++){
        int u,v;
        cin>>u>>v;
        g[u].push_back(v);
        g[v].push_back(u);
    }
    if(dfs(1)==-1)ans++;
    cout<<ans;
    return 0;
}
